    {'id': 'GS-084', 'name': 'genai-faas-ml-dependency-typosquatting-deploy', 'severity': 'critical', 'category': 'genai_security', 'message': 'Potential ML library typosquatting detected in serverless function dependency specification. Package name closely resembles canonical ML library but may be backdoored.', 'patterns': ['(?i)(torch[-_]utils|torchutils|tensor[-_]flow|tensorflow[-_]utils|sklearn[-_]utils|hugging[-_]face[-_]utils|transformers[-_]utils|numpy[-_]utils|scipy[-_]utils)[^a-z0-9]', '(?i)pip\\s+install.{0,150}(--index-url|--extra-index-url|--trusted-host).{0,200}(torch|tensorflow|sklearn|transformers|huggingface)', '(?i)(requirements\\.txt|setup\\.py|pyproject\\.toml).{0,400}(torch[-_]|tensorflow[-_]|sklearn[-_]|hugging[-_]|transformers[-_])[a-z]{3,15}[^a-z]']},
    {'id': 'GS-085', 'name': 'genai-faas-iam-overprivileged-ml-function', 'severity': 'medium', 'category': 'genai_security', 'message': 'Serverless ML function IAM configuration grants excessive permissions. Over-privileged functions enable privilege escalation via role chaining if compromised.', 'patterns': ['(?i)(Effect.*Allow|Action.*\\*).{0,200}(lambda|sagemaker|s3|rds|dynamodb|secretsmanager|iam).{0,200}(Resource.*\\*|Resource.*\\\\*)', '(?i)(iam\\.attach_role_policy|iam\\.put_user_policy|iam\\.create_policy).{0,200}(lambda|faas|inference|ml.function|model.serve)', '(?i)(AdministratorAccess|AmazonS3FullAccess|AmazonRDSFullAccess|AmazonDynamoDBFullAccess).{0,300}(lambda|function|faas|serverless)']},
    {'id': 'GS-086', 'name': 'genai-faas-event-source-injection', 'severity': 'medium', 'category': 'genai_security', 'message': 'Serverless ML function processes event source payload without input validation, enabling event injection attacks via S3/SQS/SNS/API Gateway.', 'patterns': ['(?i)(Records\\[0\\]\\[.body.\\]|event\\[.Records.\\]|event\\[.body.\\]).{0,200}(yaml\\.load\\s*\\([^)]*Loader|pickle\\.loads|marshal\\.loads|exec\\s*\\(|eval\\s*\\()', '(?i)(json\\.loads\\s*\\(\\s*event).{0,300}(?!schema|validate|sanitize|allowlist).{0,200}(model\\.predict|inference|classify|process_input)', '(?i)(s3_event|sqs_message|sns_payload|kinesis_record|dynamodb_stream).{0,200}(exec|eval|subprocess\\.run|os\\.system|__import__)']},
    {'id': 'GS-087', 'name': 'genai-faas-model-hub-no-integrity-check', 'severity': 'high', 'category': 'genai_security', 'message': 'Serverless ML function loads model from public hub without integrity verification. Compromised model hub artifacts could deliver backdoored models.', 'patterns': ['(?i)(from_pretrained|hub\\.load|torch\\.hub\\.load|tf\\.keras\\.utils\\.get_file).{0,300}(?!verify_hash|sha256|md5|checksum|integrity).{0,200}(lambda_handler|handler|predict|inference)', '(?i)(huggingface\\.co|tfhub\\.dev|pytorch\\.org/hub|github\\.com.*model).{0,200}(requests\\.get|urllib\\.request\\.urlretrieve|wget).{0,300}(?!hashlib|sha256|verify)', '(?i)(AutoModel\\.from_pretrained|pipeline\\s*\\().{0,200}(?!use_auth_token|revision|commit_hash).{0,200}(trust_remote_code\\s*=\\s*True)']},
    {'id': 'GS-088', 'name': 'genai-soc-artifact-prompt-injection-no-boundary', 'severity': 'high', 'category': 'genai_security', 'message': 'LLM SOC pipeline concatenates raw security artifacts into prompts without source boundary enforcement. Log poisoning and email content injection attacks have 80%+ success rate against unprotected models.', 'patterns': ['(?i)(log_entry|log_line|siem_event|alert_body|email_content|email_body|malware_string).{0,200}(f"|f\'|\\+\\s*"|str\\.format|%s|format\\().{0,200}(prompt|query|message|instruction|system_prompt)', '(?i)(analyze|explain|summarize|review).{0,100}(log|alert|email|artifact|sample).{0,300}(openai\\.chat|anthropic\\.messages|llm\\.invoke|chat\\.complete)(?!.*sanitize|.*strip_commands|.*boundary)', '(?i)(raw_log|unparsed_event|alert_raw|email_raw).{0,200}(concatenat|join|append|f-string|format).{0,200}(system.*content|user.*content|prompt.*text)']},
    {'id': 'GS-089', 'name': 'genai-llm-soc-no-constitutional-guardrail', 'severity': 'medium', 'category': 'genai_security', 'message': 'LLM-based security analysis pipeline lacks constitutional guardrails, making it vulnerable to artifact-embedded command injection.', 'patterns': ['(?i)(analyze|process|triage).{0,100}(malware|phishing|log|siem|alert).{0,300}(openai\\.chat\\.completions\\.create|anthropic\\.messages\\.create|llm\\.generate)(?!.*system.*security.*principle|.*guardrail|.*constitutional|.*safety_check)', '(?i)(llm_response|model_output|completion\\.text).{0,200}(return|send|forward|output|execute)(?!.*validate|.*filter|.*check|.*scan).{0,200}(analyst|user|soc|dashboard)', '(?i)(security.*analysis|threat.*intel|malware.*explain).{0,300}(no.*filter|no.*guard|no.*check|skip.*validation|bypass.*safety)']},
    {'id': 'GS-090', 'name': 'genai-consensus-sampling-insufficient-safe-models', 'severity': 'high', 'category': 'genai_security', 'message': 'Multi-model consensus sampling configuration violates Byzantine fault tolerance threshold (f >= n/2). Provable security guarantees are broken; unsafe model collusion can fully control output.', 'patterns': ['(?i)(model_group|consensus_group|model_pool|ensemble_models).{0,300}(unsafe_count|byzantine_count|compromised_count|adversarial_count).{0,200}(>=?|greater.?than|more.?than).{0,50}(safe_count|trusted_count|n\\s*/\\s*2|half)', '(?i)(n_models|total_models|group_size).{0,200}(\\b[2-9]\\b|\\b1[0-9]\\b).{0,200}(n_safe|safe_models|trusted).{0,200}(\\b1\\b|single|one).{0,200}(consensus|vote|sample)', '(?i)(consensus.sampling|reliable.consensus|model.group.safety).{0,300}(f\\s*>=?\\s*s|f\\s*>=?\\s*n\\s*/\\s*2|unsafe_fraction\\s*>=?\\s*0\\.[5-9])']},
    {'id': 'GS-091', 'name': 'genai-smart-contract-reentrancy-llm-miss', 'severity': 'high', 'category': 'genai_security', 'message': 'Smart contract contains reentrancy vulnerability (external call before state update). LLM auditors have documented blind spots for this pattern. Do not rely solely on LLM audit output.', 'patterns': ['(?i)function\\s+\\w+.{0,100}(external|public).{0,600}(\\.call\\s*\\{|address\\s*\\(\\w+\\)\\.call|\\w+\\.transfer\\s*\\(|\\.send\\s*\\().{0,400}(balances?\\s*\\[|balance\\s*=|userBalance).{0,200}(=\\s*0|\\-=\\s*|delete\\s+balances?)', '(?i)(msg\\.sender\\.call|to\\.call|addr\\.call).{0,200}\\{.{0,100}value\\s*:.{0,300}\\}.{0,400}(balances?\\s*\\[\\w+\\]\\s*-=|\\w+Balance\\s*=\\s*0|state\\s*=)', '(?i)(function\\s+(withdraw|sendFunds|sendEther|payout)\\s*\\().{0,600}(\\.call\\.value\\(|\\.call\\{value:|transfer\\s*\\(|send\\s*\\().{0,400}(balances?\\s*\\[|userFunds\\s*\\[).{0,200}(=\\s*0|\\-=)']},
    {'id': 'GS-092', 'name': 'genai-smart-contract-access-control-gap', 'severity': 'high', 'category': 'genai_security', 'message': 'Smart contract exposes privileged function without access control modifier. LLM auditors demonstrate documented blind spots for access control gaps (40 missed cases in SmartLLM study).', 'patterns': ['(?i)pragma\\s+solidity.{0,800}function\\s+\\w+.{0,100}public.{0,300}(selfdestruct\\s*\\(|delegatecall\\s*\\(|callcode\\s*\\()(?!.*require.*owner|.*onlyOwner)', '(?i)(function\\s+(mint|burn|setPrice|setBaseURI|withdraw)\\s*\\().{0,200}public(?!.*onlyOwner|.*onlyRole|.*require.*msg\\.sender.*==.*owner)']},
    {'id': 'GS-093', 'name': 'genai-mitre-t1059-llm-defense-disablement', 'severity': 'high', 'category': 'genai_security', 'message': 'LLM-generated MITRE T1059.003 payload detected: Windows security service disablement script consistent with AI-assisted T1562.001 Impair Defenses technique.', 'patterns': ['(?i)(WinDefend|wcscsvc|wuauserv|eventlog|RemoteRegistry|TermService|SamSs|wscsvc|Sense).{0,300}(Stop-Service|sc\\s+stop|net\\s+stop|Set-Service.{0,30}-Status.{0,30}Stopped|stopService)', '(?i)(DisableAntiSpyware|DisableAntiVirus|DisableRealtimeMonitoring|DisableBehaviorMonitoring).{0,200}(HKLM|HKCU|Set-ItemProperty|reg\\s+add|New-ItemProperty)', '(?i)(EnableFirewall|DisableFirewall|PrivateProfile|PublicProfile).{0,200}(WindowsFirewall|MpPreference).{0,200}(Set-ItemProperty|reg\\s+add|-Value\\s+0)']},
    {'id': 'GS-094', 'name': 'genai-mitre-t1055-llm-process-hollowing-code', 'severity': 'critical', 'category': 'genai_security', 'message': 'LLM-generated MITRE T1055.012 process hollowing code detected. AI-assisted process injection implementation found in codebase.', 'patterns': ['(?i)(CREATE_SUSPENDED|0x00000004\\s*\\|\\s*0x00000008|creation_flags.{0,30}suspended).{0,400}(VirtualAllocEx|WriteProcessMemory|SetThreadContext|NtUnmapViewOfSection)', '(?i)(ctypes\\.WinDLL\\s*\\(\\s*[\'"]kernel32|win32api\\.OpenProcess).{0,400}(VirtualAllocEx|WriteProcessMemory|SetWindowLongPtr|GWLP_USERDATA)', '(?i)(process.?hollow|process_hollow|hollow_process|inject_malicious_code).{0,400}(suspended|CREATE_SUSPENDED|map_process_memory|write_memory|inject)']},
    {'id': 'GS-095', 'name': 'genai-mitre-t1003-llm-lsass-dump-code', 'severity': 'critical', 'category': 'genai_security', 'message': 'LLM-generated MITRE T1003.001 LSASS memory dump code detected. Credential harvesting implementation consistent with AI-generated offensive tool.', 'patterns': ['(?i)(procdump.{0,30}lsass|lsass.{0,30}procdump|sekurlsa::minidump|mimikatz.{0,30}lsass|taskmgr.{0,30}dumpfile).{0,400}(subprocess|os\\.system|os\\.popen|shell=True|check_output)', '(?i)(lsass_process_name|lsass\\.exe).{0,200}(procdump_path|mimikatz_path|task_manager_args).{0,300}(subprocess\\.call|subprocess\\.run|check_output)', '(?i)(dump_methods|dump_lsass|lsass_dump).{0,300}(procdump|mimikatz|klist\\.exe|regripper|radare2).{0,300}(subprocess\\.run|subprocess\\.call|shell=True)']},
    {'id': 'GS-096', 'name': 'genai-huntgpt-xai-explainer-manipulation', 'severity': 'low', 'category': 'genai_security', 'message': 'Potential manipulation of XAI-integrated IDS pipeline detected. Crafted inputs may bias SHAP/LIME explanations to suppress anomaly detection in HuntGPT-style security tools.', 'patterns': ['(?i)(shap_value|shap_output|lime_explanation|feature_importance|feature_contribution).{0,300}(craft|manipulate|poison|suppress|falsify|bias).{0,200}(anomaly|detection|prediction|classification)', '(?i)(explainer|xai_output|explanation_json|factors_json).{0,300}(inject|tamper|modify|spoof).{0,200}(packet|network_flow|log_entry|detection)', '(?i)(false_negative|suppress_alert|evade_detection).{0,200}(shap|lime|feature.contribution|model.explanation|xai)']},
    {'id': 'CALUS-GNAI-SCAN-117', 'name': 'llm-soc-log-injection-sink', 'severity': 'critical', 'category': 'genai_security', 'message': 'Raw log data fed to LLM without sanitization — log contamination attacks can hijack model behavior (SecureCAI threat model)', 'patterns': ['(?i)(openai|anthropic|llm|chat|completion).*\\.(complete|invoke|call|generate|chat)\\s*\\(.*log(?:s|_data|_entry|_line|_content)', '(?i)(prompt|messages|content)\\s*[=+].*(?:log_line|log_entry|log_data|syslog|event_log|audit_log)(?!.*sanitize|.*filter|.*strip)']},
    {'id': 'CALUS-GNAI-SCAN-118', 'name': 'llm-email-content-injection-sink', 'severity': 'critical', 'category': 'genai_security', 'message': 'Unfiltered email content passed to LLM — adversarial email payloads can override analyst instructions', 'patterns': ['(?i)(prompt|message|content|user_message)\\s*[=+f].*(?:email(?:_body|_content|_text|_subject)|mail\\.body|mail\\.text|msg\\.payload)', '(?i)(?:analyze|classify|process)_email.*(?:openai|anthropic|llm|gpt|claude)(?!.*\\bsanitiz|.*\\bstrip_instructions|.*\\bboundary)']},
    {'id': 'CALUS-GNAI-SCAN-119', 'name': 'llm-malware-sample-injection-sink', 'severity': 'critical', 'category': 'genai_security', 'message': 'Malware sample content injected directly into LLM prompt — adversarial prompts in comments or strings can suppress detection', 'patterns': ['(?i)(prompt|content|user_input)\\s*[=+].*(?:decompile|disassem|binary_str|malware|sample_code|shellcode|payload_str)', '(?i)(?:explain|analyze|summarize)_(?:malware|binary|shellcode).*(?:llm|gpt|claude|openai)(?!.*instruction_hierarchy|.*system_prompt_sep)']},
    {'id': 'CALUS-GNAI-SCAN-120', 'name': 'missing-llm-output-validation', 'severity': 'high', 'category': 'genai_security', 'message': 'LLM output used directly in code execution without validation — an attacker-controlled prompt can execute arbitrary commands', 'patterns': ['(?i)response\\s*=\\s*(?:client|openai|llm|anthropic).*(?:complete|invoke|generate|chat)[\\s\\S]{0,200}(?:exec|subprocess|os\\.system|eval)\\s*\\(\\s*response']},
    {'id': 'CALUS-GNAI-SCAN-121', 'name': 'missing-constitutional-guardrails', 'severity': 'high', 'category': 'genai_security', 'message': 'LLM called without system prompt — missing constitutional guardrails exposes cybersecurity assistants to injection attacks', 'patterns': ['(?i)openai\\.(?:ChatCompletion|chat\\.completions)\\.create\\([^)]*messages\\s*=\\s*\\[(?![^\\]]*system)']},
    {'id': 'CALUS-GNAI-SCAN-123', 'name': 'unsafe-pickle-model-deserialization', 'severity': 'critical', 'category': 'genai_security', 'message': 'Unsafe model deserialization via pickle/torch.load — malicious model files can execute arbitrary code on load (AIRS threat 2.1)', 'patterns': ['(?i)pickle\\.(?:load|loads)\\s*\\([^)]*(?:model|weights|checkpoint|state_dict)']},
    {'id': 'CALUS-GNAI-SCAN-124', 'name': 'missing-ai-audit-trail', 'severity': 'medium', 'category': 'genai_security', 'message': 'LLM security decision made without audit trail — missing interaction logs prevent forensic traceability (AIAuditTrack requirement)', 'patterns': ['(?i)def\\s+(?:analyze|classify|detect|assess)_(?:threat|vulnerability|malware|phishing)[^:]*:[\\s\\S]{0,500}(?:openai|anthropic|llm)(?![\\s\\S]{0,500}(?:audit_log|log_request|record|trajectory))']},
    {'id': 'CALUS-GNAI-SCAN-125', 'name': 'smart-contract-llm-audit-no-verification', 'severity': 'medium', 'category': 'genai_security', 'message': 'LLM smart contract audit without verification step — unvalidated findings risk false positives and missed vulnerabilities in DeFi systems', 'patterns': ['(?i)(?:audit|scan|analyze)_(?:contract|solidity|erc).*(?:openai|llm|gpt|claude)(?![\\s\\S]{0,400}(?:verificat|rag|retriev|cross.?ref|validate_finding))', '(?i)(?:reentrancy|overflow|access.?control).*(?:detect|found|vulnerab)(?![\\s\\S]{0,200}(?:human.?review|manual.?check|verify|confirm))']},
    {'id': 'CALUS-GNAI-SCAN-126', 'name': 'llm-code-generation-no-security-scan', 'severity': 'high', 'category': 'genai_security', 'message': 'LLM-generated code executed without security scanning — most LLMs generate CWE-78/CWE-190 vulnerable code even when prompting for security', 'patterns': ['(?i)generated_code\\s*=.*(?:openai|llm|gpt|claude)(?![\\s\\S]{0,400}(?:bandit|semgrep|codeql|snyk|scan|security_check|vulnerability_scan))', '(?i)(?:write_to_file|exec|compile|subprocess)\\s*\\(\\s*(?:generated_code|llm_output|ai_code|code_snippet)(?![^)]*sanitize)']},
    {'id': 'CALUS-GNAI-SCAN-128', 'name': 'ai-supply-chain-untrusted-model-source', 'severity': 'high', 'category': 'genai_security', 'message': 'AI model loaded from HuggingFace Hub without commit hash pinning or hash verification — supply chain compromise risk', 'patterns': ['(?i)hub\\.(?:download|snapshot_download|hf_hub_download)\\s*\\([^)]*\\)(?![\\s\\S]{0,200}(?:local_files_only|cache_dir.*verify|token.*verify|sha))']},
    {'id': 'CALUS-GNAI-SCAN-129', 'name': 'lora-adapter-no-integrity-check', 'severity': 'high', 'category': 'genai_security', 'message': 'LoRA/PEFT adapter loaded without integrity check — malicious adapters can inject backdoor behaviors into the base model (AIRS 3.4)', 'patterns': ['(?i)(?:load_adapter|PeftModel\\.from_pretrained|load_peft_weights)\\s*\\([^)]*\\)(?![\\s\\S]{0,200}(?:hash|sha256|checksum|verify|adapter_hash))', '(?i)model\\.load_adapter\\s*\\([^)]*\\)(?![\\s\\S]{0,100}(?:verify|check|hash|integrity))']},
    {'id': 'CALUS-GNAI-SCAN-130', 'name': 'llm-vulnerability-detection-no-human-review', 'severity': 'medium', 'category': 'genai_security', 'message': 'LLM vulnerability detection result auto-applied without human review gate — false positives can cause unintended system changes', 'patterns': ['(?i)(?:vulnerability|vuln|cve|finding)\\s*=.*(?:llm|gpt|claude|openai)[\\s\\S]{0,400}(?:auto.?patch|auto.?fix|auto.?remediat|apply_fix|commit_patch)(?![\\s\\S]{0,200}(?:human|review|approval|confirm|manual))', '(?i)if\\s+(?:is_vulnerable|vuln_detected|has_vuln)\\s*(?:==\\s*True|:)[\\s\\S]{0,200}(?:patch|fix|remediat)(?![\\s\\S]{0,200}(?:human|review|approve|flag))']},
    {'id': 'CALUS-GNAI-SCAN-131', 'name': 'genai-fact-check-no-source-verification', 'severity': 'medium', 'category': 'genai_security', 'message': 'GenAI fact-checking without source verification — adversarially crafted content can manipulate AI verdicts (automated fact-checking as AI security issue)', 'patterns': ['(?i)def\\s+(?:fact.?check|verify.?claim|check.?misinformation)[^:]*:[\\s\\S]{0,500}(?:llm|gpt|openai|claude)(?![\\s\\S]{0,400}(?:source|reference|evidence|citation|retriev|rag|ground.?truth))', '(?i)(?:verdict|fact.?check.?result|claim.?verdict)\\s*=.*(?:llm|gpt|ai)_(?:response|output)(?![\\s\\S]{0,200}(?:source_verified|cross.?ref|evidence_check))']},
    {'id': 'CALUS-GNAI-SCAN-132', 'name': 'tokenizer-no-fingerprint-check', 'severity': 'medium', 'category': 'genai_security', 'message': 'Tokenizer loaded without fingerprint verification — modified tokenizers can introduce hidden trigger behaviors (AIRS threat 5.2)', 'patterns': ['(?i)tokenizer\\s*=\\s*(?:GPT2Tokenizer|LlamaTokenizer|BertTokenizer)\\.from_pretrained\\s*\\([^)]*\\)(?![\\s\\S]{0,100}(?:hash|verify|fingerprint))']},
    {'id': 'CALUS-GNAI-SCAN-133', 'name': 'llm-honeypot-prompt-exposure', 'severity': 'medium', 'category': 'genai_security', 'message': 'LLM honeypot system prompt may be exposed in error paths — attacker could identify deception and adjust behavior', 'patterns': ['(?i)(?:system_prompt|honeypot_prompt|role_instructions)\\s*=.*[\'"][^\'"]{20,}[\'"][\\s\\S]{0,300}(?:logger|print|response\\.send|return\\s+error)', '(?i)except\\s+(?:Exception|Error)[^:]*:[\\s\\S]{0,200}(?:str\\(|repr\\(|format\\().*(?:system_prompt|model_prompt|instructions)']},
    {'id': 'CALUS-GNAI-SCAN-134', 'name': 'cvellm-ontology-missing-source-validation', 'severity': 'medium', 'category': 'genai_security', 'message': 'CVE data fed to LLM without authoritative source verification — manipulated CVE descriptions can skew vulnerability scoring', 'patterns': ['(?i)cve_(?:description|text|data)\\s*=.*(?:requests?\\.get|fetch|urllib)(?![\\s\\S]{0,200}(?:nvd\\.nist\\.gov|cve\\.org|mitre\\.org|trusted_source))', '(?i)(?:analyze|score|assess)_cve.*(?:llm|gpt|openai)(?![\\s\\S]{0,300}(?:source_url|authoritative|nvd|mitre|verify_source))']},
    {'id': 'CALUS-GNAI-SCAN-135', 'name': 'ai-model-no-decentralized-identity', 'severity': 'medium', 'category': 'genai_security', 'message': 'Multi-agent LLM interaction without identity verification — unverified agent messages can carry injected instructions (AIAuditTrack threat)', 'patterns': ['(?i)def\\s+(?:receive_message|handle_agent_call|process_agent_request)[^:]*:[\\s\\S]{0,300}(?:agent_message|agent_response|tool_result)(?![\\s\\S]{0,400}(?:verify|did|credential|authenticate|trusted_agent|signature))', '(?i)agent\\.(?:run|invoke|call|execute)\\s*\\([^)]*message[^)]*\\)(?![\\s\\S]{0,200}(?:verify|auth|identity|did|credential))']},
    {'id': 'CALUS-GNAI-SCAN-136', 'name': 'llm-context-window-overflow-no-protection', 'severity': 'high', 'category': 'genai_security', 'message': 'No input token limit enforced — oversized inputs can overflow context window, truncating system-level security prompts', 'patterns': ['(?i)messages\\s*=\\s*\\[.*system.*\\][\\s\\S]{0,500}messages\\.(?:append|extend|insert)\\(.*user_input(?![\\s\\S]{0,200}(?:max_tokens|token_limit|truncate|len.*<|count_tokens))', '(?i)(?:user_input|artifact|content)\\s*=.*(?:request|input|data)[\\s\\S]{0,300}(?:openai|llm|anthropic)\\.(?:chat|complete)(?![\\s\\S]{0,200}(?:max_tokens|token_count|context_limit))']},
