    {'id': 'CALUS-GENAI-SCAN-317', 'name': 'agentic-transitive-dependency-install', 'severity': 'medium', 'category': 'genai_security', 'message': 'Detected dynamic package installation during agent execution. This can trigger malicious code in transitive dependencies before the intended tool is invoked.', 'patterns': ['(?i)(?:pip|npm|conda|apt).{0,10}(?:install|add).{0,60}(?:--user|--no-verify|--no-check)', '(?i)(?:subprocess|os\\.system|sh).{0,20}(?:pip|npm|conda|apt).{0,10}(?:install|add)']},
